const root = $('Webhook Invoice').first().json;
const b = root.body || root;

const order_number = String(b.order_number || b.order_id || 'б/н');
const customer_type = String(b.customer_type || 'individual');
const amount = b.amount ? Number(b.amount).toLocaleString('ru-RU') : null;
const customer_name = String(b.customer_name || '');
const preferred_contact = String(b.preferred_contact || 'telegram');

const amountLine = amount ? `\n💰 Сумма: ${amount} ₽` : '';
const nameLine = customer_name ? `\n👤 Клиент: ${customer_name}` : '';

let text;
if (customer_type === 'legal_entity') {
  const companyInn = $env.COMPANY_INN || 'уточните у менеджера';
  const companyBank = $env.COMPANY_BANK || 'уточните у менеджера';
  const companyAccount = $env.COMPANY_ACCOUNT || 'уточните у менеджера';
  const companyBik = $env.COMPANY_BIK || 'уточните у менеджера';
  text = `🧾 *Счёт на оплату — Заказ ${order_number}*${nameLine}${amountLine}\n\n📋 *Реквизиты для оплаты:*\nИНН: ${companyInn}\nБанк: ${companyBank}\nРасчётный счёт: ${companyAccount}\nБИК: ${companyBik}\n\nВ назначении платежа укажите номер заказа: ${order_number}`;
} else {
  const sbpPhone = $env.COMPANY_SBP_PHONE || 'уточните у менеджера';
  text = `💳 *Оплата по СБП — Заказ ${order_number}*${nameLine}${amountLine}\n\n📲 *Реквизиты СБП:*\nТелефон: ${sbpPhone}\n\nПосле оплаты пришлите скриншот — мы подтвердим получение.`;
}

return [{ json: { text, preferred_contact } }];
